// Normalize CoinGecko data into standard schema
const globalData = $('Get Global Data').first().json;
const pricesData = $('Get Top Prices').first().json;

const global = globalData.data || globalData;
const btcDominance = global.market_cap_percentage?.btc || global.btc_dominance || 0;
const ethDominance = global.market_cap_percentage?.eth || global.eth_dominance || 0;
const altcoinDominance = 100 - btcDominance - ethDominance;

const totalMarketCap = global.total_market_cap?.usd || global.total_market_cap_usd || 0;
const totalVolume = global.total_volume?.usd || global.total_24h_volume_usd || 0;
const marketCapChange = global.market_cap_change_percentage_24h_usd || 0;
const activeCryptos = global.active_cryptocurrencies || global.active_cryptos || 0;

const volToMcapRatio = totalMarketCap > 0 ? totalVolume / totalMarketCap : 0;

// Regime detection
let regime = 'RISK_OFF';
if (marketCapChange < -3) {
  regime = 'RISK_OFF';
} else if (btcDominance > 55) {
  regime = 'BTC_SEASON';
} else if (ethDominance > 20 && marketCapChange > 0) {
  regime = 'ETH_SEASON';
} else if (btcDominance < 45) {
  regime = 'ALT_SEASON';
} else {
  regime = 'NEUTRAL';
}

// BTC dominance trend (simplified - would need historical for real signal)
const btcPrice = pricesData.bitcoin?.usd || 0;
const btcChange = pricesData.bitcoin?.usd_24h_change || 0;
const ethPrice = pricesData.ethereum?.usd || 0;
const ethChange = pricesData.ethereum?.usd_24h_change || 0;
const solPrice = pricesData.solana?.usd || 0;
const solChange = pricesData.solana?.usd_24h_change || 0;

const normalized = {
  timestamp: new Date().toISOString(),
  total_market_cap_usd: totalMarketCap,
  total_volume_24h_usd: totalVolume,
  btc_dominance: parseFloat(btcDominance.toFixed(2)),
  eth_dominance: parseFloat(ethDominance.toFixed(2)),
  altcoin_dominance: parseFloat(altcoinDominance.toFixed(2)),
  market_cap_change_24h_pct: parseFloat(marketCapChange.toFixed(2)),
  active_cryptos: activeCryptos,
  vol_to_mcap_ratio: parseFloat(volToMcapRatio.toFixed(4)),
  regime: regime,
  btc_price: { usd: btcPrice, change_24h: parseFloat(btcChange.toFixed(2)) },
  eth_price: { usd: ethPrice, change_24h: parseFloat(ethChange.toFixed(2)) },
  sol_price: { usd: solPrice, change_24h: parseFloat(solChange.toFixed(2)) }
};

return { json: normalized };

// Signal detection based on metrics
const data = $('Normalize Metrics').first().json;

const signals = [];
const warnings = [];

// High volatility signal
if (data.vol_to_mcap_ratio > 0.15) {
  signals.push('HIGH_VOLATILITY: Vol/MCap ratio above 0.15 indicates elevated market activity');
}

// BTC dominance changes suggest rotation
if (data.btc_dominance > 55) {
  signals.push('BTC_DOMINANCE_HIGH: BTC season signal - capital flowing to BTC');
} else if (data.btc_dominance < 45) {
  signals.push('BTC_DOMINANCE_LOW: Alt season potential - capital rotating to altcoins');
}

// Market cap decline warning
if (data.market_cap_change_24h_pct < -3) {
  warnings.push('RISK_OFF: Market cap down >3% in 24h - defensive positioning');
} else if (data.market_cap_change_24h_pct > 3) {
  signals.push('BULLISH: Market cap up >3% in 24h - risk-on environment');
}

// ETH performance relative to BTC
if (data.eth_price.change_24h > data.btc_price.change_24h + 2) {
  signals.push('ETH_OUTPERFORMANCE: ETH gaining against BTC - rotation to ETH');
}

// Build regime description
let regimeDescription = '';
switch (data.regime) {
  case 'BTC_SEASON':
    regimeDescription = 'BTC dominance elevated - capital concentrated in Bitcoin';
    break;
  case 'ETH_SEASON':
    regimeDescription = 'ETH strength + positive momentum - rotation to Ethereum';
    break;
  case 'ALT_SEASON':
    regimeDescription = 'Low BTC dominance - capital flowing to altcoins';
    break;
  case 'RISK_OFF':
    regimeDescription = 'Market stress detected - risk-off positioning';
    break;
  default:
    regimeDescription = 'No clear trend - sideways market awaiting catalyst';
}

const output = {
  ...data,
  signals: signals,
  warnings: warnings,
  regime_description: regimeDescription
};

return { json: output };

// Format human-readable summary
const data = $('Signal Detection').first().json;

const date = new Date(data.timestamp);
const dateStr = date.toLocaleDateString('es-ES', { day: '2-digit', month: 'short', year: 'numeric' });
const timeStr = date.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' });

const formatCurrency = (val) => {
  if (val >= 1e12) return '$' + (val / 1e12).toFixed(2) + 'T';
  if (val >= 1e9) return '$' + (val / 1e9).toFixed(2) + 'B';
  if (val >= 1e6) return '$' + (val / 1e6).toFixed(2) + 'M';
  return '$' + val.toFixed(2);
};

const changeSign = data.market_cap_change_24h_pct >= 0 ? '+' : '';

const summary = `CRYPTO GLOBAL — ${dateStr} ${timeStr}

Market Cap Total: ${formatCurrency(data.total_market_cap_usd)} (${changeSign}${data.market_cap_change_24h_pct}% 24h)
Volumen 24h: ${formatCurrency(data.total_volume_24h_usd)} | Ratio Vol/MCap: ${data.vol_to_mcap_ratio}

DOMINANCE:
BTC: ${data.btc_dominance}% | ETH: ${data.eth_dominance}% | Alts: ${data.altcoin_dominance}%

Régimen actual: ${data.regime} — ${data.regime_description}

SEÑAL: ${data.signals.length > 0 ? data.signals.join(' | ') : 'Sin señales claras'}
${data.warnings.length > 0 ? '⚠️ ' + data.warnings.join(' | ') : ''}`;

const output = {
  ...data,
  summary: summary
};

return { json: output };

// Parse cached JSON for webhook response
const cacheData = $('Read Cache').first().json;

// Handle both binary and JSON input
let parsed;
if (typeof cacheData === 'string') {
  try {
    parsed = JSON.parse(cacheData);
  } catch (e) {
    parsed = { error: 'Invalid cache data', raw: cacheData };
  }
} else {
  parsed = cacheData;
}

return { json: parsed };
